static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard3dSquareInputSquareKernelCustomTilingData tiling;

    const gert::Shape *xShape = context->GetInputShape(0);
    const gert::Shape *wShape = context->GetInputShape(1);
    if (xShape->GetOriginShape().GetDimNum() != 5 || wShape->GetOriginShape().GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const uint64_t N   = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(0));
    const uint64_t Cin = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(1));
    const uint64_t Din = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(2));
    const uint64_t Hin = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(3));
    const uint64_t Win = static_cast<uint64_t>(xShape->GetOriginShape().GetDim(4));

    const uint64_t Cout = static_cast<uint64_t>(wShape->GetOriginShape().GetDim(0));
    const uint64_t CinW = static_cast<uint64_t>(wShape->GetOriginShape().GetDim(1));
    const uint64_t kD   = static_cast<uint64_t>(wShape->GetOriginShape().GetDim(2));
    const uint64_t kH   = static_cast<uint64_t>(wShape->GetOriginShape().GetDim(3));
    const uint64_t kW   = static_cast<uint64_t>(wShape->GetOriginShape().GetDim(4));

    if (CinW != Cin) {
        return ge::GRAPH_FAILED;
    }

    // stride=(1,1,1), padding=(0,0,0), dilation=(1,1,1)
    if (Din < kD || Hin < kH || Win < kW) {
        return ge::GRAPH_FAILED;
    }
    const uint64_t Dout = Din - kD + 1;
    const uint64_t Hout = Hin - kH + 1;
    const uint64_t Wout = Win - kW + 1;

    const uint64_t totalWorkVox = N * Dout * Hout * Wout;

    uint32_t blockDim = 24; // conservative default for 910B
    if (totalWorkVox < blockDim) {
        blockDim = static_cast<uint32_t>(totalWorkVox > 0 ? totalWorkVox : 1ULL);
        if (blockDim == 0) blockDim = 1;
    } else if (blockDim > 24u) {
        blockDim = 24u;
    }
    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_cin(static_cast<uint32_t>(Cin));
    tiling.set_cout(static_cast<uint32_t>(Cout));
    tiling.set_inD(static_cast<uint32_t>(Din));
    tiling.set_inH(static_cast<uint32_t>(Hin));
    tiling.set_inW(static_cast<uint32_t>(Win));
    tiling.set_kD(static_cast<uint32_t>(kD));
    tiling.set_kH(static_cast<uint32_t>(kH));
    tiling.set_kW(static_cast<uint32_t>(kW));
    tiling.set_outD(static_cast<uint32_t>(Dout));
    tiling.set_outH(static_cast<uint32_t>(Hout));
    tiling.set_outW(static_cast<uint32_t>(Wout));
    tiling.set_blockDim(blockDim);
    tiling.set_totalWorkVox(totalWorkVox);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *wk = context->GetWorkspaceSizes(1);
    wk[0] = 0;
    return ge::GRAPH_SUCCESS;
}

